// HubClient is the typed HTTP client used by frontend handlers.
// It wraps ClientWithResponses (generated by oapi-codegen) with convenience
// methods, structured logging, and sentinel errors.
//
// Use NewClient to construct.
type HubClient struct {
	gen     *ClientWithResponses
	baseURL string
}

var (
	// ErrNotFound is returned by client methods when the backend responds with 404.
	ErrNotFound = fmt.Errorf("not found")

	// ErrUnsupportedApp is returned when the backend responds with 422 (unknown app).
	ErrUnsupportedApp = fmt.Errorf("unsupported app")
)

// NewHubClient constructs a HubClient that targets the given backend base URL.
// backendURL must not have a trailing slash (e.g. "http://backend:8000").
// Panics if the URL is invalid.
//
// This is distinct from the oapi-codegen-generated NewClient() which returns
// the low-level (*Client, error) — NewHubClient is the constructor for
// handler code and tests.
func NewHubClient(backendURL string) *HubClient {
	hc := &http.Client{Timeout: 10 * time.Second}
	gen, err := NewClientWithResponses(backendURL, WithHTTPClient(hc))
	if err != nil {
		panic("api.NewClient: " + err.Error())
	}
	return &HubClient{gen: gen, baseURL: backendURL}
}

func logCall(op string, start time.Time, err error) {
	slog.Debug("backend call", "op", op, "ms", time.Since(start).Milliseconds(), "err", err)
}

